class Solution {
    public String lastSubstring(String s) {
        int n = s.length();
        for (int i = n - 1; i >= 0; i--) {
            for (int j = i + 1; j < n; j++) {
                String sub = s.substring(i, j + 1);
                if (isLexicographicallyMax(sub, s.substring(i + 1))) {
                    return sub;
                }
            }
        }
        return s;
    }
    private boolean isLexicographicallyMax(String a, String b) {
        for (int i = 0; i < Math.min(a.length(), b.length()); i++) {
            if (a.charAt(i) > b.charAt(i)) {
                return true;
            } else if (a.charAt(i) < b.charAt(i)) {
                return false;
            }
        }
        return a.length() > b.length();
    }
}
